    `rfp_id` BIGINT COMMENT '',
    `sales_account_id` BIGINT COMMENT 'FK to the sales account',
    `sales_agency_id` BIGINT COMMENT 'FK to the buying agency',
    `sales_contact_id` BIGINT COMMENT 'FK to the primary sales contact',
