    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `accepted_date` DATE COMMENT 'Date the proposal was accepted.',
    `accepted_timestamp` TIMESTAMP COMMENT '',
    `agency_commission_pct` DECIMAL(18,2) COMMENT 'Agency commission percentage.',
    `agency_commission_rate` DECIMAL(18,2) COMMENT 'Agency commission rate applied to the proposal.',
    `approved_date` DATE COMMENT 'Date proposal was approved/accepted',
    `approved_timestamp` TIMESTAMP COMMENT '',
    `audience_guarantee_flag` BOOLEAN COMMENT '',
    `cancellation_terms` STRING COMMENT 'Cancellation terms and penalty description',
    `channel_mix_summary` STRING COMMENT '',
    `commission_rate` DECIMAL(18,2) COMMENT 'Agency commission rate',
    `cpm` DECIMAL(18,2) COMMENT 'Proposed cost per thousand impressions.',
    `cpp` DECIMAL(18,2) COMMENT 'Proposed cost per rating point.',
