    `daypart` STRING COMMENT 'Targeted daypart for placements.',
    `daypart_mix` STRING COMMENT 'Description of proposed daypart distribution.',
    `decision_date` DATE COMMENT 'Date the proposal was accepted or rejected.',
    `discount_amount` DECIMAL(18,2) COMMENT 'Total discount applied to the proposal.',
    `discount_pct` DECIMAL(18,2) COMMENT 'Negotiated discount percentage.',
    `discount_percent` DECIMAL(18,2) COMMENT 'Negotiated discount percentage',
    `discount_percentage` DECIMAL(18,2) COMMENT '',
    `discount_rate` DECIMAL(18,2) COMMENT 'Negotiated discount rate applied to rate card.',
    `estimated_grp` DECIMAL(18,2) COMMENT 'Estimated gross rating points delivered.',
    `estimated_grps` DECIMAL(18,2) COMMENT 'Estimated gross rating points.',
    `estimated_impressions` BIGINT COMMENT 'Estimated total impressions delivered.',
    `expiration_date` DATE COMMENT 'Date proposal expires if not accepted',
    `expiry_date` DATE COMMENT '',
    `flight_end_date` DATE COMMENT 'Campaign flight end date',
    `flight_start_date` DATE COMMENT 'Campaign flight start date',
    `gross_amount` DECIMAL(18,2) COMMENT 'Gross dollar amount before discounts/commission.',
    `guarantee_flag` BOOLEAN COMMENT 'Whether delivery is guaranteed.',
    `is_political` BOOLEAN COMMENT 'Flag indicating political advertising proposal.',
    `is_revised_flag` BOOLEAN COMMENT 'True if this proposal is a revision of a prior version.',
    `last_modified_timestamp` TIMESTAMP COMMENT '',
    `makegood_eligible_flag` BOOLEAN COMMENT 'Whether shortfalls qualify for makegoods.',
    `makegood_policy` STRING COMMENT 'Makegood policy terms description',
    `proposal_name` STRING COMMENT 'Human-readable name of the proposal',
    `net_amount` DECIMAL(18,2) COMMENT 'Net amount after agency commission.',
    `net_proposed_value` DECIMAL(18,2) COMMENT '',
    `notes` STRING COMMENT 'Free-text notes on the proposal',
    `platform_mix` STRING COMMENT 'Platform allocation mix (linear/digital/CTV percentages)',
    `proposal_date` DATE COMMENT '',
    `proposal_number` STRING COMMENT 'Human-readable proposal reference number.',
    `proposal_status` STRING COMMENT 'Lifecycle status (draft, submitted, accepted, rejected, expired).',
    `proposal_type` STRING COMMENT 'Proposal type (upfront, scatter, sponsorship, digital).',
    `proposed_cpm` DECIMAL(18,2) COMMENT 'Proposed cost-per-mille rate.',
    `proposed_frequency` DECIMAL(18,2) COMMENT '',
