CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`sales`.`private_marketplace_deal` (
    `private_marketplace_deal_id` BIGINT COMMENT '',
    `advertiser_id` BIGINT COMMENT '',
    `dsp_id` BIGINT COMMENT '',
    `exchange_id` BIGINT COMMENT 'The exchange id associated with each private marketplace deal record, used to capture and track this specific business attribute.',
    `ssp_id` BIGINT COMMENT '',
    `_created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `_updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    `auction_type` STRING COMMENT 'Auction type (first-price, second-price).',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `currency` STRING COMMENT 'Deal trading currency.',
    `deal_external_code` STRING COMMENT 'PMP deal ID exchanged with SSP/DSP',
    `deal_id_external` STRING COMMENT 'External OpenRTB PMP deal ID.',
    `deal_name` STRING COMMENT 'Human-readable deal name.',
    `deal_status` STRING COMMENT 'Deal status',
    `deal_type` STRING COMMENT 'Preferred/private auction/programmatic guaranteed',
    `end_date` DATE COMMENT '',
    `floor_price` DECIMAL(18,2) COMMENT 'Bid floor price for the deal.',
    `floor_price_cpm` DECIMAL(18,2) COMMENT 'The floor price cpm associated with each private marketplace deal record, used to capture and track this specific business attribute.',
    `is_active` BOOLEAN COMMENT '',
    `is_active_flag` BOOLEAN COMMENT 'Whether the deal is currently active.',
    `priority` STRING COMMENT '',
    `source_record_code` STRING COMMENT 'Identifier in source system',
    `start_date` DATE COMMENT '',
    `private_marketplace_deal_status` STRING COMMENT '',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_private_marketplace_deal PRIMARY KEY(`private_marketplace_deal_id`)
) COMMENT 'Private marketplace (PMP) deal with negotiated deal ID.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`sales`.`bid_response` (
    `bid_response_id` BIGINT COMMENT '',
    `advertiser_id` BIGINT COMMENT 'Advertiser identifier',
    `bid_request_id` BIGINT COMMENT '',
    `campaign_id` BIGINT COMMENT 'Campaign identifier from DSP',
    `dsp_id` BIGINT COMMENT '',
    `private_marketplace_deal_id` BIGINT COMMENT 'Associated PMP deal',
    `ssp_id` BIGINT COMMENT 'FK to the SSP.',
    `_created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `_updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    `bid_price` DECIMAL(18,2) COMMENT 'Bid price submitted.',
    `bid_price_cpm` DECIMAL(18,2) COMMENT 'Submitted bid CPM',
    `clearing_price` DECIMAL(18,2) COMMENT 'Clearing/winning price.',
    `clearing_price_cpm` DECIMAL(18,2) COMMENT 'Winning clearing price CPM',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `creative_code` STRING COMMENT 'Creative identifier in the response.',
    `currency` STRING COMMENT 'Currency of the bid.',
    `is_pmp_flag` BOOLEAN COMMENT 'Whether this is a PMP deal',
    `is_sampled_flag` BOOLEAN COMMENT 'Sampled telemetry flag',
    `is_win` BOOLEAN COMMENT 'Whether the bid won the auction',
    `is_win_flag` BOOLEAN COMMENT 'Auction win flag',
    `loss_reason_code` STRING COMMENT 'OpenRTB loss reason code if not won.',
    `nurl` STRING COMMENT 'Win notice URL',
    `nurl_fired_flag` BOOLEAN COMMENT 'Whether the win-notification URL was fired.',
    `openrtb_bid_code` STRING COMMENT 'OpenRTB bid id field.',
    `openrtb_response_code` STRING COMMENT 'OpenRTB response id',
    `responded_at` TIMESTAMP COMMENT 'Timestamp of the bid response.',
    `response_latency_ms` STRING COMMENT '',
    `response_timestamp` TIMESTAMP COMMENT '',
    `seat_code` STRING COMMENT 'Buyer seat that placed the bid.',
    `source_record_code` STRING COMMENT 'Identifier in source system',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    `win_flag` BOOLEAN COMMENT 'Whether the bid won the auction.',
    `win_rate` DECIMAL(18,2) COMMENT '',
    CONSTRAINT pk_bid_response PRIMARY KEY(`bid_response_id`)
) COMMENT 'Sampled OpenRTB bid response telemetry capturing bid price, win/loss status, and clearing price for programmatic analytics and attribution models.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`sales`.`bid_request` (
    `bid_request_id` BIGINT COMMENT '',
    `dsp_id` BIGINT COMMENT 'FK to the DSP receiving the request.',
    `exchange_id` BIGINT COMMENT '',
    `private_marketplace_deal_id` BIGINT COMMENT '',
    `sales_device_type_id` BIGINT COMMENT 'Foreign key linking to sales.sales_device_type. Business justification: bid_request currently stores device_type as a raw STRING column, which is a classic ENUM-REF-CANDIDATE. sales_device_type is a promoted reference table for exactly this purpose. Adding sales_device_ty',
    `ssp_id` BIGINT COMMENT '',
    `_created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `_updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    `ad_format` STRING COMMENT 'Requested ad format (video, display, audio).',
    `ad_size` STRING COMMENT 'Requested ad size',
    `bid_floor` DECIMAL(18,2) COMMENT 'Bid floor sent in the request.',
    `country_code` STRING COMMENT 'Geo country code of the request.',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `currency` STRING COMMENT 'Currency of the bid floor.',
    `floor_price_cpm` DECIMAL(18,2) COMMENT '',
    `geo_country` STRING COMMENT '',
    `geo_dma` STRING COMMENT 'The geo dma associated with each bid request record, used to capture and track this specific business attribute.',
    `impression_code` STRING COMMENT 'OpenRTB impression id.',
    `impression_type` STRING COMMENT 'video/display/audio',
    `is_pmp_flag` BOOLEAN COMMENT 'Whether this is a PMP deal',
    `is_sampled` BOOLEAN COMMENT '',
    `is_sampled_flag` BOOLEAN COMMENT 'Sampled telemetry flag',
    `is_secure_flag` BOOLEAN COMMENT 'Whether the impression requires HTTPS.',
    `openrtb_request_code` STRING COMMENT 'OpenRTB bid request id',
    `request_timestamp` TIMESTAMP COMMENT '',
    `requested_at` TIMESTAMP COMMENT 'Timestamp of the bid request.',
    `sample_rate` DECIMAL(18,2) COMMENT 'Sampling rate',
    `source_record_code` STRING COMMENT 'Identifier in source system',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
