    CONSTRAINT pk_bid_request PRIMARY KEY(`bid_request_id`)
) COMMENT 'Sampled OpenRTB bid request telemetry capturing programmatic auction parameters for win-rate and clearing-price analysis in multi-touch attribution and MMM demos.';

