CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`sales`.`sales_channel` (
    `sales_channel_id` BIGINT COMMENT 'Primary key for sales_channel',
    `parent_sales_channel_id` BIGINT COMMENT 'Self-referencing FK on sales_channel (parent_sales_channel_id)',
    `_created_at` TIMESTAMP COMMENT 'Timestamp when this sales channel record was first created in the data platform (yyyy-MM-ddTHH:mm:ss.SSSXXX). Part of the standardised cross-domain audit trail per VREQ-035 to support medallion bronzeâ†’silverâ†’gold lineage tracing.',
    `_source_system` STRING COMMENT 'Name of the operational system of record from which this sales channel record was sourced (e.g., Salesforce Media Cloud, WideOrbit, Operative.One). Supports medallion bronzeâ†’silverâ†’gold lineage tracing per VREQ-035 cross-domain timestamp/lineage standard.',
    `_updated_at` TIMESTAMP COMMENT 'Timestamp when this sales channel record was last modified in the data platform (yyyy-MM-ddTHH:mm:ss.SSSXXX). Part of the standardised cross-domain audit trail per VREQ-035 to support change detection and incremental processing in the medallion architecture.',
    `ai_ad_disclosure_required` BOOLEAN COMMENT 'Indicates whether AI-generated advertising content disclosure is required for ads placed through this channel, per FCC AI ad disclosure rules and EU AI Act requirements. When True, triggers C2PA/generative-AI content provenance flagging in the content_provenance workflow.',
    `audience_guarantee_supported` BOOLEAN COMMENT 'Indicates whether this sales channel supports audience-guaranteed deals (True), where delivery is guaranteed against a demographic target (e.g., Adults 18-49 GRP guarantee). Relevant for upfront and scatter TV sales with Nielsen or Comscore measurement.',
    `avails_source_system` STRING COMMENT 'Name of the system that provides inventory availability (avails) data for this sales channel (e.g., WideOrbit, FreeWheel, Operative.One, Nielsen Avails). Used for avails integration and inventory management workflows.',
    `billing_frequency` STRING COMMENT 'Frequency at which invoices are generated for orders transacted through this sales channel: weekly, biweekly, monthly, quarterly, upon_delivery (post-air billing), or upon_execution (pre-pay/upfront). Drives billing cycle configuration in the OMS and accounts receivable.',
    `channel_category` STRING COMMENT 'Media category served by this sales channel, indicating the inventory type sold through it: linear_tv (broadcast/cable), streaming (OTT/AVOD/FAST), digital (display/video online), radio, out_of_home, print, or multiplatform (cross-platform bundles). Used for revenue segmentation and audience reporting.',
    `channel_code` STRING COMMENT 'Short, externally-known alphanumeric code uniquely identifying the sales channel (e.g., DIRECT, AGENCY, PROG, BARTER). Used as a stable business key in downstream joins and Salesforce Media Cloud picklist values. Referenced by sales_channel_ref_id across the sales domain.',
    `channel_name` STRING COMMENT 'Human-readable full name of the sales channel (e.g., Direct Sales, Agency / Rep Firm, Programmatic, Barter/Trade). Displayed in reports, dashboards, and Salesforce opportunity records.',
    `channel_status` STRING COMMENT 'Current lifecycle status of the sales channel record: active (available for use in proposals and orders), inactive (temporarily disabled), deprecated (retired, no new business), or pilot (in limited trial). Controls availability in Salesforce picklists and rate card assignments.',
    `channel_type` STRING COMMENT 'Broad classification of the sales channel by commercial model: direct (sold by internal sales team), agency (sold through ad agency or rep firm), programmatic (automated/algorithmic buying), barter (trade/exchange deals), self_serve (advertiser-direct digital portal), or partner (reseller/affiliate). Drives commission structures and revenue recognition rules.',
    `children_programming_flag` BOOLEAN COMMENT 'Indicates whether this channel primarily airs childrens programming subject to COPPA and FCC Childrens Television Act restrictions (True). Restricts certain ad categories and data collection practices on this channel.',
    `content_rating_restriction` STRING COMMENT 'Maximum content rating permitted for advertising or content sold/distributed through this channel, based on TV Parental Guidelines or MPAA ratings (e.g., TV-G, TV-PG, TV-14, TV-MA). Enforces brand safety and regulatory compliance for ad placement.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the primary country in which this sales channel operates (e.g., USA, GBR, CAN). Used for international revenue segmentation, regulatory compliance, and multi-territory deal management.',
    `credit_terms_days` STRING COMMENT 'Standard payment credit terms in calendar days applicable to invoices generated from orders on this sales channel (e.g., 30 = Net 30, 45 = Net 45). Used by billing to set invoice due dates and aging buckets.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the primary currency in which deals are transacted through this sales channel (e.g., USD, GBP, EUR). Supports multi-currency operations for international distribution and licensing channels.',
    `daypart_applicability` STRING COMMENT 'Comma-separated list or description of dayparts for which this sales channel is applicable (e.g., Primetime, Late Night, Daytime). Informs rate card applicability and scheduling constraints. Free-text to accommodate complex multi-daypart configurations.',
    `sales_channel_description` STRING COMMENT 'Free-text business description of the sales channel, including its purpose, scope, applicable inventory types, and any special commercial terms or restrictions. Used for internal documentation and onboarding of new sales staff.',
    `effective_end_date` DATE COMMENT 'Date after which this sales channel record is no longer valid for new business (yyyy-MM-dd). Null indicates an open-ended/indefinitely active channel. Used to retire deprecated channels while preserving historical order references.',
    `effective_start_date` DATE COMMENT 'Date from which this sales channel record is valid and available for use in proposals, orders, and rate cards (yyyy-MM-dd). Supports temporal validity management for channel lifecycle changes.',
    `fcc_license_required` BOOLEAN COMMENT 'Indicates whether FCC broadcast licensing requirements apply to this sales channel (True for over-the-air broadcast channels, False for cable/streaming/digital channels). Drives compliance workflow routing for political advertising and equal opportunity rules.',
    `floor_cpm` DECIMAL(18,2) COMMENT 'Minimum acceptable CPM (Cost Per Thousand Impressions) for programmatic or digital inventory sold through this channel. Prevents below-floor-price transactions in programmatic auctions and private marketplace deals. Expressed in the channels primary currency.',
    `geographic_scope` STRING COMMENT 'Geographic coverage scope of the sales channel: national (network-wide), local (single market/DMA), regional (multi-market cluster), international (cross-border), dma_specific (single Nielsen DMA), or network (full network footprint). Drives market-level revenue reporting and rate card applicability.',
    `go_to_market_model` STRING COMMENT 'The commercial go-to-market model associated with this sales channel, indicating how inventory is sold and priced: upfront (annual advance commitments), scatter (spot market), direct_response (performance-based), sponsorship, branded_content, programmatic_guaranteed, private_marketplace (PMP), or open_exchange. Determines pricing methodology and deal structure. [ENUM-REF-CANDIDATE: upfront|scatter|direct_response|sponsorship|branded_content|programmatic_guaranteed|private_marketplace|open_exchange â€” promote to reference product]',
    `inventory_type` STRING COMMENT 'Primary type of advertising inventory sold through this channel. [ENUM-REF-CANDIDATE: spot|sponsorship|product_placement|branded_content|interstitial|overlay|banner|pre_roll|mid_roll|post_roll â€” promote to reference product]',
    `is_agency_commission_eligible` BOOLEAN COMMENT 'Indicates whether standard agency commission (typically 15% of gross billing) applies to deals transacted through this sales channel. Drives commission calculation logic in billing and accounts receivable.',
    `is_digital` BOOLEAN COMMENT 'Indicates whether this sales channel is a digital/online channel (True) as opposed to a traditional linear/broadcast channel (False). Used to segment digital vs. traditional revenue reporting and apply appropriate IAB digital standards.',
    `is_programmatic` BOOLEAN COMMENT 'Indicates whether this sales channel supports programmatic/automated buying (True). Drives application of programmatic supply chain transparency rules (ads.txt, sellers.json) and OpenRTB protocol requirements.',
    `makegoods_policy` STRING COMMENT 'Policy governing how audience delivery shortfalls (under-delivery) are remedied for orders on this channel: standard (replacement spots), no_makegoods (no remedy), cash_credit_only (billing credit), or equivalent_value (comparable inventory substitution). Critical for upfront and scatter deal management.',
    `measurement_currency` STRING COMMENT 'The audience measurement currency used to value and guarantee inventory sold through this channel: grp (Gross Rating Point), trp (Target Rating Point), impression (digital impression), reach, cpm (Cost Per Mille), cpcv (Cost Per Completed View), ctr (Click-Through Rate), or vcr (View Completion Rate). Determines how proposals are priced and delivery is reconciled.',
    `measurement_provider` STRING COMMENT 'Name of the third-party audience measurement provider used to validate delivery and audience guarantees for this channel (e.g., Nielsen, Comscore, DoubleVerify, IAS, Moat). Governs which measurement data is used for post-campaign reconciliation and makegood calculations.',
    `minimum_order_value` DECIMAL(18,2) COMMENT 'Minimum gross order value (in the channels primary currency) required to transact business through this sales channel. Enforced during proposal and order creation to ensure channel viability thresholds are met.',
    `network_affiliation` STRING COMMENT 'Name of the broadcast network or cable/streaming network with which this sales channel is affiliated (e.g., NBC, CBS, ESPN, Peacock, Tubi). Relevant for local affiliate stations and MVPD/vMVPD distribution channels.',
    `notes` STRING COMMENT 'Free-text operational notes or comments about this sales channel, such as known system integration quirks, special billing instructions, or temporary policy exceptions. Intended for internal use by sales operations and data stewards.',
    `order_management_system` STRING COMMENT 'Name or identifier of the order management system (OMS) that processes confirmed orders originating from this sales channel (e.g., WideOrbit, Operative.One, FreeWheel OMS, Mediaocean). Drives downstream trafficking and billing integration routing.',
    `owned_operated_flag` BOOLEAN COMMENT 'Indicates whether this sales channel is owned and operated (O&O) by the media company (True) or is an affiliate/third-party channel (False). O&O channels have different revenue recognition, commission, and reporting treatment.',
    `platform` STRING COMMENT 'The technology platform or system through which sales are transacted on this channel (e.g., Salesforce Media Cloud, FreeWheel, Google Ad Manager, Operative.One, WideOrbit, Magnite, SpotX). Used for system-of-record routing and integration mapping. [ENUM-REF-CANDIDATE: promote to reference product if platform list exceeds 6 entries]',
    `political_advertising_eligible` BOOLEAN COMMENT 'Indicates whether this sales channel is eligible to carry political advertising (True). FCC-licensed broadcast channels must comply with equal opportunity and lowest unit rate (LUR) rules for political candidates. Triggers compliance workflows and special rate card rules.',
    `rate_card_applicability` STRING COMMENT 'Indicates which type of rate card applies to inventory sold through this channel: standard (published rate card), negotiated (custom deal rates), programmatic (floor price/CPM-based), barter (non-cash exchange), or no_rate_card (free/house use). Governs pricing logic in proposal generation.',
    `rep_firm_commission_rate` DECIMAL(18,2) COMMENT 'Commission rate payable to a national or local sales representative firm for business transacted through this channel, expressed as a decimal fraction. Applicable when the channel is managed by an external rep firm rather than an internal sales team.',
    `rep_firm_name` STRING COMMENT 'Name of the national or local sales representative firm contracted to sell inventory on behalf of this channel (e.g., Katz Media Group, Petry Media, Cox Reps). Applicable when the channel is not sold exclusively by an internal direct sales team.',
    `revenue_stream` STRING COMMENT 'Primary revenue stream generated through this sales channel: advertising (spot/display ad sales), content_licensing (IP licensing fees), syndication (content distribution fees), distribution (carriage/affiliate fees), barter (trade exchange), sponsorship (integrated brand deals), or affiliate (performance-based referral). Feeds revenue recognition and financial reporting by channel.',
    `sales_team_assignment` STRING COMMENT 'Name or code of the internal sales team or division responsible for managing and selling through this channel (e.g., National Sales, Local Sales, Digital Sales, Programmatic Revenue). Used for quota assignment, commission attribution, and Salesforce territory management.',
    `sort_order` STRING COMMENT 'Numeric display sort order for this sales channel in UI picklists, reports, and dashboards. Lower values appear first. Allows business users to control the presentation sequence of channels in Salesforce and analytics tools.',
    `standard_agency_commission_rate` DECIMAL(18,2) COMMENT 'Default agency commission rate applied to gross billing for deals transacted through this channel, expressed as a decimal fraction (e.g., 0.1500 = 15%). Used in billing calculations when no deal-specific commission override is present. Confidential commercial rate.',
    `trafficking_system` STRING COMMENT 'The ad trafficking or ad server system used to execute and deliver campaigns sold through this channel (e.g., FreeWheel MRM, Google Ad Manager, WideOrbit Traffic, Extreme Reach). Links sales channel to delivery infrastructure for campaign execution.',
    CONSTRAINT pk_sales_channel PRIMARY KEY(`sales_channel_id`)
) COMMENT 'Master reference table for sales_channel. Referenced by sales_channel_ref_id.';

